import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database } from './types';
import { SUPABASE_CONFIGURED, SUPABASE_PUBLISHABLE_KEY, SUPABASE_URL } from './config';

/**
 * True when Supabase credentials are present in the environment.
 * When false, the app runs in local mode: auth is bypassed, edge functions
 * are skipped, and the dashboard loads directly without a login wall.
 */
export { SUPABASE_CONFIGURED } from './config';

let supabasePromise: Promise<SupabaseClient<Database>> | null = null;

export async function getSupabaseClient(): Promise<SupabaseClient<Database>> {
  if (!SUPABASE_CONFIGURED || !SUPABASE_URL || !SUPABASE_PUBLISHABLE_KEY) {
    throw new Error('Supabase not configured');
  }

  if (supabasePromise === null) {
    supabasePromise = import('@supabase/supabase-js').then(({ createClient }) =>
      createClient<Database>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY, {
        auth: {
          storage: localStorage,
          persistSession: true,
          autoRefreshToken: true,
        },
      })
    );
  }

  return supabasePromise;
}
